actions.script:
import groovy.json.JsonOutput
import groovy.json.JsonSlurper
import java.net.http.HttpClient
import java.net.http.HttpRequest
import java.net.http.HttpResponse
import java.time.Duration

success = false
publishedUrl = null
errorMessage = null

try {
    def sessionToken = platformConfig.apiKey
    def publicationUrl = platformConfig.username?.replaceAll('/+$', '')

    if (!sessionToken) {
        errorMessage = "Substack session token (apiKey) not configured"
        return
    }
    if (!publicationUrl) {
        errorMessage = "Substack publication URL (username) not configured"
        return
    }

    // Build Prosemirror document from finalContent (split on blank lines = paragraphs)
    def paragraphs = (post.finalContent as String).split(/\n\n+/).collect { para ->
        def lines = para.trim()
        if (!lines) return null
        [
            type: "paragraph",
            content: [[type: "text", text: lines]]
        ]
    }.findAll { it != null }

    if (!paragraphs) {
        paragraphs = [[type: "paragraph", content: [[type: "text", text: post.finalContent as String]]]]
    }

    def prosemirrorDoc = [type: "doc", content: paragraphs]

    def requestBody = [
        draft_title:    post.headline ?: "",
        draft_subtitle: post.draftContent ?: "",
        draft_body:     JsonOutput.toJson(prosemirrorDoc),
        draft_bylines:  [],
        audience:       "everyone"
    ]

    def hostname = new URL(publicationUrl).host
    def apiUrl = "${publicationUrl}/api/v1/drafts"
    def cookieHeader = "substack.sid=${sessionToken}; connect.sid=${sessionToken}"

    def httpClient = HttpClient.newBuilder()
        .connectTimeout(Duration.ofSeconds(15))
        .build()

    def request = HttpRequest.newBuilder()
        .uri(URI.create(apiUrl))
        .header("Content-Type", "application/json")
        .header("Cookie", cookieHeader)
        .header("Referer", "${publicationUrl}/publish/post")
        .header("Origin", publicationUrl)
        .POST(HttpRequest.BodyPublishers.ofString(JsonOutput.toJson(requestBody)))
        .timeout(Duration.ofSeconds(30))
        .build()

    def response = httpClient.send(request, HttpResponse.BodyHandlers.ofString())
    def responseBody = response.body()

    ec.logger.info("Substack API response [${response.statusCode()}]: ${responseBody?.take(500)}")

    if (response.statusCode() in [200, 201]) {
        def parsed = new JsonSlurper().parseText(responseBody)
        def draftId = parsed?.id
        publishedUrl = draftId ? "${publicationUrl}/publish/post/${draftId}" : "${publicationUrl}/publish"
        success = true
    } else {
        errorMessage = "Substack API error ${response.statusCode()}: ${responseBody?.take(300)}"
    }

} catch (Exception e) {
    errorMessage = "Substack publishing failed: ${e.message}"
    ec.logger.error("Substack publish error", e)
}

import groovy.json.JsonOutput
import groovy.json.JsonSlurper
import java.net.http.HttpClient
import java.net.http.HttpRequest
import java.net.http.HttpResponse
import java.time.Duration

success = false
publishedUrl = null
errorMessage = null

try {
    def accessToken = platformConfig.apiKey
    def personUrn   = platformConfig.username

    if (!accessToken) {
        errorMessage = "LinkedIn access token (apiKey) not configured"
        return
    }
    if (!personUrn) {
        errorMessage = "LinkedIn person URN (username) not configured — expected format: urn:li:person:XXXXX"
        return
    }

    // Build post text: headline + finalContent
    def postText = new StringBuilder()
    if (post.headline) postText.append(post.headline).append("\n\n")
    postText.append(post.finalContent ?: "")

    def requestBody = [
        author: personUrn,
        lifecycleState: "PUBLISHED",
        specificContent: [
            "com.linkedin.ugc.ShareContent": [
                shareCommentary: [
                    text: postText.toString()
                ],
                shareMediaCategory: "NONE"
            ]
        ],
        visibility: [
            "com.linkedin.ugc.MemberNetworkVisibility": "PUBLIC"
        ]
    ]

    def httpClient = HttpClient.newBuilder()
        .connectTimeout(Duration.ofSeconds(15))
        .build()

    def request = HttpRequest.newBuilder()
        .uri(URI.create("https://api.linkedin.com/v2/ugcPosts"))
        .header("Authorization", "Bearer ${accessToken}")
        .header("Content-Type", "application/json")
        .header("X-Restli-Protocol-Version", "2.0.0")
        .POST(HttpRequest.BodyPublishers.ofString(JsonOutput.toJson(requestBody)))
        .timeout(Duration.ofSeconds(30))
        .build()

    def response = httpClient.send(request, HttpResponse.BodyHandlers.ofString())
    def responseBody = response.body()

    ec.logger.info("LinkedIn API response [${response.statusCode()}]: ${responseBody?.take(500)}")

    if (response.statusCode() == 201) {
        // LinkedIn returns the post URN in X-RestLi-Id header
        def postUrn = response.headers().firstValue("X-RestLi-Id").orElse(null)
        if (postUrn) {
            // URN format: urn:li:ugcPost:XXXXXXXXXX
            def postId = postUrn.tokenize(':').last()
            publishedUrl = "https://www.linkedin.com/feed/update/${postUrn}/"
        } else {
            publishedUrl = "https://www.linkedin.com/feed/"
        }
        success = true
    } else {
        errorMessage = "LinkedIn API error ${response.statusCode()}: ${responseBody?.take(300)}"
    }

} catch (Exception e) {
    errorMessage = "LinkedIn publishing failed: ${e.message}"
    ec.logger.error("LinkedIn publish error", e)
}
